INSERT INTO `skp_perilaku_pegawai` (`id`, `NAMA`, `NIP`, `NAMA_ATASAN_LANGSUNG`, `NIP_ATASAN_LANGSUNG`, `PERILAKU_KERJA_BERORIENTASI_PELAYANAN`, `PERILAKU_KERJA_AKUNTABEL`, `PERILAKU_KERJA_KOMPETEN`, `PERILAKU_KERJA_HARMONIS`, `PERILAKU_KERJA_LOYAL`, `PERILAKU_KERJA_ADAPTIF`, `PERILAKU_KERJA_KOLABORATIF`, `EKSPEKTASI_PIMPINAN_BERORIENTASI_PELAYANAN`, `EKSPEKTASI_PIMPINAN_AKUNTABEL`, `EKSPEKTASI_PIMPINAN_KOMPETEN`, `EKSPEKTASI_PIMPINAN_HARMONIS`, `EKSPEKTASI_PIMPINAN_LOYAL`, `EKSPEKTASI_PIMPINAN_ADAPTIF`, `EKSPEKTASI_PIMPINAN_KOLABORATIF`, `UMPAN_BALIK_BERORIENTASI_PELAYANAN`, `UMPAN_BALIK_AKUNTABEL`, `UMPAN_BALIK_KOMPETEN`, `UMPAN_BALIK_HARMONIS`, `UMPAN_BALIK_LOYAL`, `UMPAN_BALIK_ADAPTIF`, `UMPAN_BALIK_KOLABORATIF`, `TRIWULAN`, `TAHUN`, `STATUS`, `TANGGAL_INPUT_SKP`, `ID_SKP_GLOBAL`, `PANGKAT_GOL_RUANG`, `JABATAN`, `UNIT_KERJA`, `SATUAN_KERJA`) VALUES
(15, 'Dolly Wattimena, S.H. MM', '199510072020122001', 'Meydi Zulqadri, S.H.,M.H', '198705132010121006', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Ekspektasi Khusus Pimpinan : Memberikan layanan yang cepat dan ramah,\r\nBersedia ditegur dan memperbaiki kesalahan yang dilakukan', 'Ekspektasi Khusus Pimpinan : Melaksanakan tugas dengan jujur dan\r\nbertanggung jawab serta menjunjung tinggi integritas pegawai', 'Ekspektasi Khusus Pimpinan : Menyelesaikan setiap pekerjaan sesuai\r\ndengan target dan standar kualitas yang ditetapkan', 'Ekspektasi Khusus Pimpinan : Saling membantu dengan rekan kerja di\r\nBagian Tata Usaha dan Umum, khususnya pekerjaan yang perlu diselesaikan\r\ntepat waktu', 'Ekspektasi Khusus Pimpinan : Utamakan tugas dan fungsi sebagai ASN\r\ndiatas kepentingan pribadi/golongan', 'Ekspektasi Khusus Pimpinan : Bersedia mengikuti pembinaan dan\r\npengembangan kompetensi', 'Ekspektasi Khusus Pimpinan : Bangun kerjasama yang baik dengan Instansi\r\nterkait untuk kelancaran pelaksanaan Tugas dan Fungsi', 'Pelayanan Kepegawaian yang diberikan sudah Sangat Baik, pertahankan.', 'Baik. Tetap junjung tinggi Integritas dan profesionalitas pegawai', 'Baik. Tetap kerjakan tugas sesuai SOP dan aturan yang berlaku.', 'Baik. Pertahankan komunikasi dan hubungan baik yang telah terjalin dengan Instansi terkait', 'Baik. Tetap bekerja dengan profesional, jaga nama baik diri, pimpinan dan Institusi', 'Perlu ditingkatkan lagi inovasi dan kreativitas dalam bekerja', 'Baik. Pertahankan kerjasama yang baik yang telah terjalin selama ini dengan Instansi terkait untuk kelancaran tugas', 1, 2025, 'DRAFT', '2025-10-27 09:56:25', 1, NULL, NULL, NULL, NULL),
