 NULL, NULL, NULL, NULL, NULL, NULL, NULL, 4, 2026, 'draft', '2026-04-29 01:36:54', 88, ' Penata Muda Tk. I / IIIb', 'Penata Kelola Pemerintahan', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
