ULL, NULL, NULL, NULL, NULL, NULL, NULL, 3, 2026, 'draft', '2026-04-29 19:53:36', 207, 'Pengatur /Iic', 'Pengadministrasi Perkantoran', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
