ik', 'baik', 'baik', 'baik', 'baik', 'baik', 1, 2026, 'SELESAI EVALUASI', '2026-04-30 00:25:48', 461, 'Penata Tk. I / IIId', 'Penata Kelola Pemerintahan', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
